CREATE USER 'Admin'@'localhost' IDENTIFIED BY 'Admin123';
CREATE USER 'ChefProjet'@'localhost' IDENTIFIED BY 'Projet456';
CREATE USER 'Stagiaire'@'localhost' IDENTIFIED BY 'Stag789';

GRANT SELECT, INSERT, UPDATE, DELETE ON Societe_Vente.Commandes TO 'ChefProjet'@'localhost';
GRANT SELECT, UPDATE ON Societe_Vente.Produits TO 'ChefProjet'@'localhost';
GRANT SELECT ON Societe_Vente.Employes TO 'ChefProjet'@'localhost';

Justification : Le chef de projet a besoin de gérer les commandes (tous droits). Il doit pouvoir modifier le stock des produits (UPDATE) mais pas créer/supprimer des produits (pas DELETE/INSERT). Il peut voir les employés (SELECT) mais ne doit pas modifier leurs salaires (pas UPDATE).

-- 1. Révoquer tous les privilèges existants
REVOKE ALL PRIVILEGES, GRANT OPTION FROM 'Stagiaire'@'%';

-- 2. Donner uniquement SELECT sur la table Produits
GRANT SELECT ON Societe_Vente.Produits TO 'Stagiaire'@'%';

-- 3. Appliquer les modifications
FLUSH PRIVILEGES;
